#include <bits/stdc++.h>
using namespace std;

int main() {
    int n, ans1 = 1, ans2 = 0;
    cin >> n;
    while (n) {
        if (n % 3 == 1 && !ans2) {
            ans2 = ans1;
        }
        n -= ceil(n / 3.0);
        ans1++;
    }
    ans1--;
    printf("%d %d", ans1, ans2);
    return 0;
}
